async function writePermitData() {
  console.log('Writing permit/access data to routes.access column...\n');

  // Get all routes to batch process
  const PAGE = 1000;
  let totalRoutes = 0;
  let updated = 0;
  let unmodified = 0;

  let from = 0;

  for (;;) {
    const { data: allRoutes, error: fetchError } = await supabase
      .from('routes')
      .select('id, area_id, name')
      .range(from, from + PAGE - 1);

    if (fetchError) {
      console.error('Fetch error:', fetchError);
      process.exit(1);
    }

    if (!allRoutes || !allRoutes.length) break;

    // Batch update routes that have permit data
    for (const route of allRoutes) {
      totalRoutes++;
      if (permitData[route.area_id]) {
        const accessData = permitData[route.area_id];
        const { error: updateError } = await supabase
          .from('routes')
          .update({ access: accessData })
          .eq('id', route.id);

        if (updateError) {
          console.error(`Error updating route ${route.id}:`, updateError);
        } else {
          updated++;
        }
      } else {
        unmodified++;
      }
    }

    if (allRoutes.length < PAGE) break;
    from += PAGE;
  }

  console.log(`\nSummary:`);
  console.log(`  Total routes processed: ${totalRoutes}`);
  console.log(`  Updated with permit data: ${updated}`);
  console.log(`  No permit data available: ${unmodified}`);
  console.log(`\nPermit data write complete.`);
}

writePermitData().catch(console.error);
